import express from "express";
import dotenv from "dotenv";

dotenv.config();

const app = express();

app.get("/api/places", async (req, res) => {
  const url = `https://api.geoapify.com/v2/places?categories=commercial.supermarket&bias=proximity:10.7389701,59.9133301&limit=20&apiKey=${process.env.GEOAPIFY_API_KEY}`;

  const response = await fetch(url);
  const data = await response.json();

  res.json(data);
});

app.listen(3000, () => {
  console.log("Server running on port 3000");
});